import sqlite3

def get_order(user_id, order_id):
    # Connect to the SQLite database
    conn = sqlite3.connect('orders.db')
    cursor = conn.cursor()
    
    # Prepare the SQL query with parameterized inputs to prevent SQL injection
    query = "SELECT * FROM orders WHERE user_id = ? AND order_id = ?"
    
    # Execute the query with the provided parameters
    cursor.execute(query, (user_id, order_id))
    
    # Fetch the first row of the result
    order_data = cursor.fetchone()
    
    # Close the database connection
    conn.close()
    
    # Return the order data as a dictionary if found, otherwise return None
    if order_data:
        return dict(zip([description[0] for description in cursor.description], order_data))
    else:
        return None